import{_ as e,o as a,c as l,a2 as r}from"./chunks/framework.BQ1gajhD.js";const f=JSON.parse('{"title":"北京天文馆","description":"","frontmatter":{},"headers":[],"relativePath":"museums/planetarium.md","filePath":"museums/planetarium.md","lastUpdated":null}'),n={name:"museums/planetarium.md"};function d(i,t,s,o,h,g){return a(),l("div",null,[...t[0]||(t[0]=[r('<h1 id="北京天文馆" tabindex="-1">北京天文馆 <a class="header-anchor" href="#北京天文馆" aria-label="Permalink to &quot;北京天文馆&quot;">​</a></h1><blockquote><p>&quot;探索宇宙奥秘，仰望星空梦想。&quot;</p></blockquote><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>北京天文馆位于北京市西城区，是中国第一座大型天文馆，也是亚洲最大的天文馆之一。天文馆通过天象表演、展览、互动体验等方式，向公众普及天文学知识，激发人们对宇宙的好奇和探索欲望。</p><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>开放时间</strong></td><td style="text-align:left;">9:00-16:30（周一、周二闭馆）</td></tr><tr><td style="text-align:left;"><strong>门票价格</strong></td><td style="text-align:left;">展厅10元，剧场30-45元</td></tr><tr><td style="text-align:left;"><strong>建议游玩</strong></td><td style="text-align:left;">2-3小时</td></tr><tr><td style="text-align:left;"><strong>最佳季节</strong></td><td style="text-align:left;">四季皆宜</td></tr><tr><td style="text-align:left;"><strong>交通方式</strong></td><td style="text-align:left;">地铁4号线动物园站</td></tr><tr><td style="text-align:left;"><strong>地址</strong></td><td style="text-align:left;">北京市西城区西直门外大街138号</td></tr></tbody></table><h2 id="历史沿革" tabindex="-1">历史沿革 <a class="header-anchor" href="#历史沿革" aria-label="Permalink to &quot;历史沿革&quot;">​</a></h2><h3 id="创建" tabindex="-1">创建 <a class="header-anchor" href="#创建" aria-label="Permalink to &quot;创建&quot;">​</a></h3><p>北京天文馆筹建于1955年，1957年9月29日正式开馆，是新中国成立后的第一座大型科普场馆。</p><h3 id="老馆时期" tabindex="-1">老馆时期 <a class="header-anchor" href="#老馆时期" aria-label="Permalink to &quot;老馆时期&quot;">​</a></h3><p>天文馆老馆建筑面积约8000平方米，由天象厅、展览厅等组成。</p><h3 id="新馆建设" tabindex="-1">新馆建设 <a class="header-anchor" href="#新馆建设" aria-label="Permalink to &quot;新馆建设&quot;">​</a></h3><p>2004年，天文馆新馆建成。新馆建筑面积2.4万平方米，拥有世界上最先进的天象厅。</p><h2 id="建筑特色" tabindex="-1">建筑特色 <a class="header-anchor" href="#建筑特色" aria-label="Permalink to &quot;建筑特色&quot;">​</a></h2><h3 id="外观" tabindex="-1">外观 <a class="header-anchor" href="#外观" aria-label="Permalink to &quot;外观&quot;">​</a></h3><p>北京天文馆由A馆（老馆）和B馆（新馆）组成。</p><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">描述</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>A馆（老馆）</strong></td><td style="text-align:left;">圆形穹顶，黄色</td></tr><tr><td style="text-align:left;"><strong>B馆（新馆）</strong></td><td style="text-align:left;">现代建筑，玻璃幕墙</td></tr><tr><td style="text-align:left;"><strong>总建筑</strong></td><td style="text-align:left;">约3.2万平方米</td></tr></tbody></table><h2 id="主要场馆" tabindex="-1">主要场馆 <a class="header-anchor" href="#主要场馆" aria-label="Permalink to &quot;主要场馆&quot;">​</a></h2><h3 id="a馆-老馆" tabindex="-1">A馆（老馆） <a class="header-anchor" href="#a馆-老馆" aria-label="Permalink to &quot;A馆（老馆）&quot;">​</a></h3><h4 id="天象厅" tabindex="-1">天象厅 <a class="header-anchor" href="#天象厅" aria-label="Permalink to &quot;天象厅&quot;">​</a></h4><p>天象厅是北京天文馆的核心设施，可以模拟真实的星空。</p><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">数据</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>穹顶直径</strong></td><td style="text-align:left;">23.5米</td></tr><tr><td style="text-align:left;"><strong>座位数</strong></td><td style="text-align:left;">约600个</td></tr><tr><td style="text-align:left;"><strong>设备</strong></td><td style="text-align:left;">蔡司天象仪</td></tr><tr><td style="text-align:left;"><strong>特点</strong></td><td style="text-align:left;">可模拟全天星空</td></tr></tbody></table><h4 id="展览" tabindex="-1">展览 <a class="header-anchor" href="#展览" aria-label="Permalink to &quot;展览&quot;">​</a></h4><p>老馆有多个展览，包括：</p><ul><li><strong>太阳展览</strong>：介绍太阳的知识</li><li><strong>月球展览</strong>：介绍月球的知识</li><li><strong>行星展览</strong>：介绍八大行星</li></ul><h3 id="b馆-新馆" tabindex="-1">B馆（新馆） <a class="header-anchor" href="#b馆-新馆" aria-label="Permalink to &quot;B馆（新馆）&quot;">​</a></h3><h4 id="宇宙剧场" tabindex="-1">宇宙剧场 <a class="header-anchor" href="#宇宙剧场" aria-label="Permalink to &quot;宇宙剧场&quot;">​</a></h4><p>宇宙剧场是新馆的核心设施，采用数字天象仪，可以播放各种天文影片。</p><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">数据</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>穹顶直径</strong></td><td style="text-align:left;">18米</td></tr><tr><td style="text-align:left;"><strong>座位数</strong></td><td style="text-align:left;">约200个</td></tr><tr><td style="text-align:left;"><strong>设备</strong></td><td style="text-align:left;">数字天象仪</td></tr><tr><td style="text-align:left;"><strong>特点</strong></td><td style="text-align:left;">3D效果震撼</td></tr></tbody></table><h4 id="_4d剧场" tabindex="-1">4D剧场 <a class="header-anchor" href="#_4d剧场" aria-label="Permalink to &quot;4D剧场&quot;">​</a></h4><p>4D剧场可以播放4D电影，有震动、喷水、刮风等特效。</p><h4 id="太阳观测台" tabindex="-1">太阳观测台 <a class="header-anchor" href="#太阳观测台" aria-label="Permalink to &quot;太阳观测台&quot;">​</a></h4><p>太阳观测台可以观测太阳，包括太阳黑子、日珥等。</p><h4 id="展览-1" tabindex="-1">展览 <a class="header-anchor" href="#展览-1" aria-label="Permalink to &quot;展览&quot;">​</a></h4><p>新馆有丰富的展览：</p><ul><li><strong>宇宙展区</strong>：介绍宇宙的起源和演化</li><li><strong>太阳家族</strong>：介绍太阳系</li><li><strong>陨石展区</strong>：展示各种陨石</li><li><strong>望远镜展区</strong>：介绍望远镜的历史</li></ul><h2 id="珍贵展品" tabindex="-1">珍贵展品 <a class="header-anchor" href="#珍贵展品" aria-label="Permalink to &quot;珍贵展品&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">展品</th><th style="text-align:left;">说明</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>陨石</strong></td><td style="text-align:left;">各种陨石，包括铁陨石、石陨石等</td></tr><tr><td style="text-align:left;"><strong>月球岩石</strong></td><td style="text-align:left;">阿波罗计划带回的月球岩石（复制品）</td></tr><tr><td style="text-align:left;"><strong>古代天文仪器</strong></td><td style="text-align:left;">浑天仪、简仪等</td></tr><tr><td style="text-align:left;"><strong>望远镜</strong></td><td style="text-align:left;">各种天文望远镜</td></tr></tbody></table><h2 id="天象表演" tabindex="-1">天象表演 <a class="header-anchor" href="#天象表演" aria-label="Permalink to &quot;天象表演&quot;">​</a></h2><h3 id="表演内容" tabindex="-1">表演内容 <a class="header-anchor" href="#表演内容" aria-label="Permalink to &quot;表演内容&quot;">​</a></h3><p>天文馆的天象表演是必看项目，可以体验身临其境的星空。</p><table tabindex="0"><thead><tr><th style="text-align:left;">剧场</th><th style="text-align:left;">内容</th><th style="text-align:center;">票价</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>天象厅</strong></td><td style="text-align:left;">《奇妙的星空》</td><td style="text-align:center;">45元</td></tr><tr><td style="text-align:left;"><strong>宇宙剧场</strong></td><td style="text-align:left;">《宇宙大爆炸》《星空音乐会》等</td><td style="text-align:center;">30元</td></tr><tr><td style="text-align:left;"><strong>4D剧场</strong></td><td style="text-align:left;">《太空探险》等</td><td style="text-align:center;">30元</td></tr></tbody></table><h3 id="推荐节目" tabindex="-1">推荐节目 <a class="header-anchor" href="#推荐节目" aria-label="Permalink to &quot;推荐节目&quot;">​</a></h3><ul><li><strong>《奇妙的星空》</strong>：天象厅经典节目，带你认识四季星座</li><li><strong>《宇宙大爆炸》</strong>：宇宙起源的科普片</li><li><strong>《星空音乐会》</strong>：音乐与星空的完美结合</li></ul><h2 id="太阳观测" tabindex="-1">太阳观测 <a class="header-anchor" href="#太阳观测" aria-label="Permalink to &quot;太阳观测&quot;">​</a></h2><p>天文馆设有太阳观测台，可以观测太阳。</p><h3 id="观测内容" tabindex="-1">观测内容 <a class="header-anchor" href="#观测内容" aria-label="Permalink to &quot;观测内容&quot;">​</a></h3><ul><li><strong>太阳黑子</strong>：太阳表面的黑色斑点</li><li><strong>日珥</strong>：太阳表面的火焰状物质</li><li><strong>太阳望远镜</strong>：通过望远镜观测太阳</li></ul><h2 id="游览攻略" tabindex="-1">游览攻略 <a class="header-anchor" href="#游览攻略" aria-label="Permalink to &quot;游览攻略&quot;">​</a></h2><h3 id="预约须知" tabindex="-1">预约须知 <a class="header-anchor" href="#预约须知" aria-label="Permalink to &quot;预约须知&quot;">​</a></h3><ol><li><strong>提前预约</strong>：建议提前预约剧场票</li><li><strong>剧场票热销</strong>：热门节目票源紧张</li><li><strong>周一、周二闭馆</strong>：注意开放时间</li></ol><h3 id="推荐路线" tabindex="-1">推荐路线 <a class="header-anchor" href="#推荐路线" aria-label="Permalink to &quot;推荐路线&quot;">​</a></h3><p><strong>经典路线（约2-3小时）</strong>：</p><p>A馆展览 → 天象厅表演 → B馆展览 → 宇宙剧场/4D剧场 → 太阳观测</p><p><strong>亲子路线</strong>：</p><p>B馆宇宙展区 → 4D剧场 → 天象厅 → A馆展览</p><h3 id="交通方式" tabindex="-1">交通方式 <a class="header-anchor" href="#交通方式" aria-label="Permalink to &quot;交通方式&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">方式</th><th style="text-align:left;">站点</th></tr></thead><tbody><tr><td style="text-align:left;">地铁</td><td style="text-align:left;">4号线动物园站D口</td></tr><tr><td style="text-align:left;">公交</td><td style="text-align:left;">7路、15路、19路等动物园站</td></tr><tr><td style="text-align:left;">步行</td><td style="text-align:left;">从北京北站步行约15分钟</td></tr></tbody></table><h3 id="实用贴士" tabindex="-1">实用贴士 <a class="header-anchor" href="#实用贴士" aria-label="Permalink to &quot;实用贴士&quot;">​</a></h3><ol><li><strong>剧场必看</strong>：天象厅和宇宙剧场的表演必看</li><li><strong>提前预约</strong>：剧场票建议提前预约</li><li><strong>亲子游</strong>：非常适合带孩子参观</li><li><strong>避开高峰</strong>：周末人较多，建议工作日</li><li><strong>结合游览</strong>：可与北京动物园一起游览</li><li><strong>观测天气</strong>：太阳观测需晴天</li></ol><h2 id="周边景点" tabindex="-1">周边景点 <a class="header-anchor" href="#周边景点" aria-label="Permalink to &quot;周边景点&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">景点</th><th style="text-align:center;">距离</th><th style="text-align:left;">特色</th></tr></thead><tbody><tr><td style="text-align:left;">北京动物园</td><td style="text-align:center;">紧邻</td><td style="text-align:left;">大熊猫</td></tr><tr><td style="text-align:left;">北京展览馆</td><td style="text-align:center;">步行10分钟</td><td style="text-align:left;">展览中心</td></tr><tr><td style="text-align:left;">西直门商圈</td><td style="text-align:center;">地铁1站</td><td style="text-align:left;">商业区</td></tr><tr><td style="text-align:left;">什刹海</td><td style="text-align:center;">地铁2站</td><td style="text-align:left;">老北京风情</td></tr></tbody></table><h2 id="教育意义" tabindex="-1">教育意义 <a class="header-anchor" href="#教育意义" aria-label="Permalink to &quot;教育意义&quot;">​</a></h2><p>北京天文馆是国家级科普教育基地，承担着向公众普及天文学知识的重要使命。</p><p>天文馆通过生动的展览和震撼的天象表演，激发孩子们对宇宙的好奇和探索欲望，是亲子游的绝佳选择。</p><hr><p><strong>📍 地址</strong>：北京市西城区西直门外大街138号 <strong>📞 电话</strong>：010-68353003 <strong>🌐 官网</strong>：<a href="http://www.bjp.org.cn" target="_blank" rel="noreferrer">www.bjp.org.cn</a></p>',67)])])}const b=e(n,[["render",d]]);export{f as __pageData,b as default};
